  addNewEnvList = () => 
	{
		var ItemCount =this.state.EnvURIList.length
		this.setState({loader:true})
		if(ItemCount>0)
		{
			var valuecheck = this.state.EnvURIList[ItemCount-1].EnvName
			//console.log(valuecheck);
			if(valuecheck.trim()==="")
			{
				this.setState({loader:false})
				this.setState({modal:true})
			    return this.setState({modalValidationText:'Please add information on blank row, before adding new row'})
			}
		}
		var lastOneId = this.state.EnvURIList.length + 1;
		this.setState({ EnvURIList: [...this.state.EnvURIList, {
			id: `${lastOneId}`, EnvName: ``,URIValue:``
		}] });
		this.setState({loader:false});
	}
